Sounds great!  Look forward to your changes and I'll make a pull request for the .d.ts file.  For right now I am just initializing a static member so that it is available later.
```ts
export class DurableHost<M extends EventBase, S extends StateBase> {
  private static _host: Host<any,any>;
  static init(host: Host<any, any>) {
    this._host = host;
  }
  public get host() { return DurableHost._host; }

  private rulesetName: string;
  private get rulesetName() { return this.rulesetName; }

  constructor(rulesetName: string) {
    this.rulesetName = rulesetName;
  }

  public post(event: M) {
    return this.host.post(this.rulesetName, event);
  }

  public assert(fact: M) {
    return this.host.assert(this.rulesetName, fact);
  }

  public patchState(contextState: S) {
    return this.host.patchState(this.rulesetName, contextState);
  }
}
```

